#include<bits/stdc++.h> 
using namespace std;
#define ll long long
stack<int> st;
const int N=100005;
ll n,a[N],s[N],ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;
	st.push(0);
	a[0]=-0x3f3f3f3f;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		s[i]=s[i-1]+a[i];
	}
	for(int i=1;i<=n;i++)
	{
		while(!st.empty()&&a[st.top()]>a[i])
		{
			int tmp=st.top();
			st.pop();
			ans=max(ans,a[tmp]*(s[i-1]-s[st.top()]));
//			cout<<a[tmp]*(s[i-1]-s[st.top()])<<"   min : "<<a[tmp]<<"  l : "<<st.top()+1<<"  r: "<<i-1<<"\n";
		}
		st.push(i);
	}
	while(st.top()!=0)
	{
		int tmp=st.top();
		st.pop();
		ans=max(ans,a[tmp]*(s[n]-s[st.top()]));
//		cout<<a[tmp]*(s[n]-s[st.top()])<<"   min : "<<a[tmp]<<"  l : "<<st.top()+1<<"  r: "<<n<<"\n";
	}
	cout<<ans;
	return 0;
}
